            aWandererC = aWandererC + (((RotL64(aCross, 57U) + aOrbiterA) + RotL64(aOrbiterF, 52U)) + RotL64(aCarry, 23U));
            aWandererD = aWandererD ^ (((RotL64(aScatter, 21U) + aOrbiterE) + RotL64(aOrbiterI, 57U)) + aPhaseBWandererUpdateSaltD[((aIndex + 8U)) & S_SALT1]);
