            aWandererA = aWandererA ^ ((RotL64(aScatter, 5U) + aOrbiterF) + RotL64(aOrbiterK, 29U));
            aWandererK = aWandererK + (((RotL64(aPrevious, 13U) + RotL64(aOrbiterH, 43U)) + aOrbiterB) + RotL64(aCarry, 51U));
            aWandererF = aWandererF ^ (((RotL64(aCross, 51U) + aOrbiterC) + RotL64(aOrbiterE, 35U)) + aPhaseBWandererUpdateSaltF[(((31U - aIndex) + 25U)) & S_SALT1]);
            aWandererI = aWandererI + ((RotL64(aIngress, 43U) + RotL64(aOrbiterD, 11U)) + aOrbiterE);
            aWandererB = aWandererB ^ ((RotL64(aScatter, 34U) + aOrbiterB) + RotL64(aOrbiterI, 22U));
