            aOrbiterG = ((aWandererD + RotL64(aCross, 57U)) + RotL64(aCarry, 51U)) + 0xD11C64F4E1BD5C93ULL;
            aOrbiterJ = (((aWandererJ + RotL64(aScatter, 43U)) + RotL64(aCarry, 11U)) + 0xA5501858CEDCC63AULL) + aPhaseGOrbiterAssignSaltF[((aIndex + 28U)) & S_SALT1];
            aOrbiterB = (aWandererG + RotL64(aPrevious, 36U)) + 0x784994D9C827A62AULL;
            //
            aOrbiterE = (aOrbiterE + aOrbiterF) + 0xA5B28FAD3D4A9274ULL;
