            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0x2FEBB35774F85E9AULL;
            aOrbiterA = RotL64((aOrbiterA * 0xA69C82F2776AC1F7ULL), 57U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterK) + 0x98B7BA2FADC6F164ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterA) ^ 0xB499491ED9C8E7E2ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x1812592267696FD7ULL), 19U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterJ) + 0x05457A707DEF54E2ULL) + aPhaseGOrbiterUpdateSaltA[((aIndex + 25U)) & S_SALT1];
            aOrbiterE = ((aOrbiterE ^ aOrbiterG) ^ 0xAC4AEE799769F810ULL) ^ aPhaseGOrbiterUpdateSaltF[((aIndex + 14U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0x5F22D5D1E5CB57ABULL), 13U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterB) + 0xE52592B30D299F34ULL) + aPhaseGOrbiterUpdateSaltD[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterD) ^ 0xDF0AB1E5A380A544ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xA0C9F9E7409AF72DULL), 37U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 0x63D34E1AC19CA67DULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0x1FB028C114347497ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x39581B79BF1137D7ULL), 53U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterE) + 0x378DD546FC0FC6ECULL) + aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterI) ^ 0x8A51C9D8B7F68106ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x2A3F702E762E185DULL), 35U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 0xC8D3C72F8C4060ACULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0x3A8C9FC955D42EF2ULL;
