            aOrbiterC = RotL64((aOrbiterC * 0xDBED4C3A8D7146EBULL), 41U);
            //
            aIngress = aOrbiterF ^ RotL64(aOrbiterB, 11U);
            aIngress = aIngress + (RotL64(aOrbiterA, 3U) ^ aOrbiterK);
            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterC, 35U));
            aIngress = aIngress + (RotL64(aOrbiterH, 53U) ^ aOrbiterJ);
            aIngress = aIngress + (RotL64(aOrbiterI, 24U) ^ aOrbiterD);
