            aOrbiterD = (((aWandererF + RotL64(aScatter, 44U)) + RotL64(aCarry, 43U)) + 0xFA834CAAF9825FABULL) + aPhaseHOrbiterAssignSaltB[((aIndex + 26U)) & S_SALT1];
