            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0x741A254C6D4BF117ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 0xD03D8C86EB692B05ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xB6B46198CA781D2DULL), 27U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0x9949B67ACF3F368BULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 0xC65469C4564CFADEULL;
            aOrbiterI = RotL64((aOrbiterI * 0x21DDCEE53F30ECFBULL), 37U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 0xCB2C87EADEC2F66FULL;
            aOrbiterB = ((aOrbiterB ^ aOrbiterK) ^ 0xB6170534D3CA9D25ULL) ^ aPhaseHOrbiterUpdateSaltE[((aIndex + 20U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0x65EA455521384F1FULL), 41U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterG) + 0x11741273550582D4ULL;
