            //
            aOrbiterB = ((aOrbiterB + aOrbiterJ) + 0x8A554C0C6F590BDBULL) + aPhaseHOrbiterUpdateSaltB[((aIndex + 5U)) & S_SALT1];
            aOrbiterA = ((aOrbiterA ^ aOrbiterB) ^ 0xBDA862C61347E814ULL) ^ aPhaseHOrbiterUpdateSaltD[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xE4C1A8EF5DBD3CE5ULL), 47U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterD) + 0x6AC4513166C4DA90ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterF) ^ 0x9C6307A71A6C276DULL;
            aOrbiterK = RotL64((aOrbiterK * 0x68310D7DD6788BD9ULL), 11U);
