            aWandererJ = aWandererJ + (((RotL64(aScatter, 19U) + RotL64(aOrbiterG, 23U)) + aOrbiterI) + aPhaseHWandererUpdateSaltC[(((31U - aIndex) + 13U)) & S_SALT1]);
            aWandererF = aWandererF ^ ((RotL64(aCross, 37U) + RotL64(aOrbiterI, 58U)) + aOrbiterB);
            aWandererB = aWandererB + (((RotL64(aPrevious, 23U) + RotL64(aOrbiterK, 11U)) + aOrbiterH) + RotL64(aCarry, 37U));
