            aWandererC = aWandererC + (((RotL64(aScatter, 53U) + RotL64(aOrbiterH, 53U)) + aOrbiterD) + aPhaseHWandererUpdateSaltB[(((31U - aIndex) + 6U)) & S_SALT1]);
            //
