            //
            aOrbiterF = ((aOrbiterF + aOrbiterC) + 0x6A80FC0602A7C090ULL) + aPhaseHOrbiterUpdateSaltC[((aIndex + 19U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 0x0AABA40C7633279CULL;
            aOrbiterH = RotL64((aOrbiterH * 0xBDB1305A4CF2511BULL), 43U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterB) + 0x0530C63C3A35A656ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0x146E130153786329ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x93C18C8E75C278CBULL), 51U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 0x193DD6316A749685ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterE) ^ 0x63A0E09926F5A1F0ULL;
            aOrbiterA = RotL64((aOrbiterA * 0xA9E09DE0CACE6F27ULL), 23U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterD) + 0x4EC89CE899B7B868ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterA) ^ 0xDCBF6E47D8E1D0DAULL;
            aOrbiterF = RotL64((aOrbiterF * 0xD4F3E08E94F51339ULL), 35U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterJ) + 0x93DE57A1D1347C48ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterH) ^ 0x0ACAAE5A103C83F5ULL) ^ aPhaseHOrbiterUpdateSaltD[((aIndex + 24U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0xAD42FDB8E2271641ULL), 19U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 0x92B90EFCE89D44F1ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterJ) ^ 0xF77D35D49347985EULL;
            aOrbiterB = RotL64((aOrbiterB * 0xEBBF71E970CE5E0FULL), 27U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterA) + 0x86C87A0E711D672AULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterB) ^ 0x93F66092BD85A7F0ULL) ^ aPhaseHOrbiterUpdateSaltE[((aIndex + 16U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0x71060217E765E351ULL), 5U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterF) + 0xCCF55A55041EB88AULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterG) ^ 0xF415E549AC53CF04ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x4965DED9AEBB345BULL), 47U);
            //
            aIngress = RotL64(aOrbiterJ, 60U) ^ aOrbiterF;
            aIngress = aIngress + (RotL64(aOrbiterB, 19U) ^ aOrbiterG);
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterH, 57U));
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterA, 53U));
            aIngress = aIngress + RotL64(aOrbiterD, 41U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererI = aWandererI ^ ((RotL64(aScatter, 47U) + RotL64(aOrbiterD, 51U)) + aOrbiterE);
            aWandererK = aWandererK + (((RotL64(aPrevious, 29U) + RotL64(aOrbiterA, 18U)) + aOrbiterB) + aPhaseHWandererUpdateSaltF[((aIndex + 13U)) & S_SALT1]);
